external_knowledge:
- 'High rate of using drones' refers to an adoption rate greater than 20%;
- 'Income categories' refer to groups of farms with similar income characteristics;
- 'More than half their money from dairy' means the proportion of income from dairy products is over 50%.

sql:
SELECT avg_income
FROM farm_incomes
WHERE region = 'North';

SELECT AVG(proportion_of_income_from_dairy) AS avg_dairy_proportion
FROM farm_incomes
WHERE crop_type = 'Dairy';

SELECT impact_value 
FROM policy_impact 
WHERE policy_id = 1;

SELECT f.*, fi.*
FROM farmers f
JOIN farm_incomes fi ON f.income_id = fi.income_id;

SELECT tech_name 
FROM technologies 
WHERE implementation_date > '2020-01-01';

external_knowledge:
- "seasoned sowers" refers to farmers with extensive experience;
- "wisdom of college" stands for having a college education level;
- "over a decade and a half in the field" means 15 years or more of experience;
- "annual bounty greater than the gold of ten thousand dollars" represents an average income greater than $10,000.

sql:
SELECT income_id, AVG(proportion_of_income_from_dairy) AS average_dairy_revenue_share
FROM farm_incomes
GROUP BY income_id;

SELECT tech_id, adoption_rate 
FROM technology_adoption 
WHERE adoption_rate = (SELECT MAX(adoption_rate) FROM technology_adoption);

SELECT policy_id, SUM(effectiveness) AS total_effectiveness
FROM policy_interventions
GROUP BY policy_id;

SELECT policy_name
FROM policies
WHERE policy_id NOT IN (
  SELECT policy_id
  FROM policy_interventions
);

SELECT farmer_name, income_id 
FROM farmers 
WHERE income_id = (SELECT MAX(income_id) FROM farmers);

SELECT effectiveness 
FROM policy_interventions 
WHERE policy_id = 0 AND effectiveness > 0.1;
